import java.util.stream.Collectors;

@AllArgsConstructor
public class ControleRszKwartaalGrensVrijwilligeBrandweerOld implements ControleRszKwartaalGrensVrijwilligeBrandweer {

    public static final Set<MoneyKey> VR_BR_RSZ_KEYS = ImmutableSet.of(
            RekenBasisRszKey.BASIS_RSZ_KEY,
            RekenRszKey.BIJDRAGE_RSZ_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_MEER_DAN_10WERKNEMERS_KEY);

    private static final Set<RszppoKategorie> IS_CATEGORIE_VRIJWILLIGE_BRANDWEER =
            Sets.immutableEnumSet(RszppoKategorie.BR_HA, RszppoKategorie.BR_HA_PR, RszppoKategorie.BR_HA_PU, RszppoKategorie.BR_HA_PR_J,
                    RszppoKategorie.BR_HA_PU_J, RszppoKategorie.BR_HA_PR_B, RszppoKategorie.BR_HA_PU_B, RszppoKategorie.BR_HA_PR_D,
                    RszppoKategorie.BR_HA_PU_D, RszppoKategorie.BR_HO, RszppoKategorie.BR_HO_PR, RszppoKategorie.BR_HO_PU, RszppoKategorie.BR_HO_PR_J,
                    RszppoKategorie.BR_HO_PU_J, RszppoKategorie.BR_HO_PR_B, RszppoKategorie.BR_HO_PU_B, RszppoKategorie.BR_HO_PR_D,
                    RszppoKategorie.BR_HO_PU_D);

    private final ConstantManager constantManager;
    private final RegimeRszppoService regimeRszppoService;

    private static Money berekenBasisRszVoorGrensVrBr(LoonElementManager manager) {
        Money basis = Money.ZERO;
        Collection<LoonElement> loonElementen = manager.getPersoonsElementen();
        for (LoonElement element : loonElementen) {
            Opper opper = element.getOpper();
            if (isVrijwilligeBrandweer(opper.getRszppo().getCategorie())) {
                basis = basis.add(element.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY));
            }
        }
        return basis;
    }

    private static boolean isVrijwilligeBrandweer(RszppoKategorie categorie) {
        return IS_CATEGORIE_VRIJWILLIGE_BRANDWEER.contains(categorie);
    }

    private static boolean isOpdrachtVrijwilligeBrandweer(Opdracht opdracht) {
        boolean test = false;
        for (Opper opper : opdracht.getOpperSlices()) {
            test = isVrijwilligeBrandweer(opper.getRszppo().getCategorie());
            if (test) {
                break;
            }
        }
        return test;
    }

    public void controleer(
            Persoon persoon, RekenTijd rekenTijd, LoonElementManager manager, List<RekenHoofd> kwartaalResultaten,
            List<Opdracht> opdrachtenKwartaal, RegulManager regulManager) {
        MoneyMap<OpdrachtDatumKey> keyToBasisRsz = new HashMoneyMap<>();
        Money basis = analyseerKwartaalResultatenVrBr(kwartaalResultaten, keyToBasisRsz, rekenTijd.beginDatum);
        basis = basis.add(berekenBasisRszVoorGrensVrBr(manager));

        Money grens = constantManager.getActualConstant(Konstanten.KST_GRENS_RSZ_VRIJW_BRW, rekenTijd).getMoney();
        if (basis.compareTo(grens) <= 0) {
            zetOpNulRszVrBr(manager);
        }

        analyseerHuidigeMaandVrBr(manager, keyToBasisRsz, rekenTijd);

        boolean regul = false;
        for (Money basisRsz : keyToBasisRsz.values()) {
            if ((basisRsz.signum() == 0 && basis.compareTo(grens) > 0) || (basisRsz.signum() > 0 && basis.compareTo(grens) <= 0)) {
                regul = true;
                break;
            }
        }

        if (regul) {
            Set<Integer> opdrachtids = new HashSet<>();
            kwartaalResultaten.stream().filter(x -> isVrijwilligeBrandweer(x.getCategorie())).map(RekenHoofd::getOpdracht).map(Opdracht::getId)
                    .forEach(opdrachtids::add);
            persoon.getOpdrachten()
                    .stream()
                    .filter(ControleRszKwartaalGrensVrijwilligeBrandweerOld::isOpdrachtVrijwilligeBrandweer)
                    .map(Opdracht::getId)
                    .forEach(opdrachtids::add);
            opdrachtenKwartaal = opdrachtenKwartaal.stream().filter(x -> opdrachtids.contains(x.getId())).collect(Collectors.toList());
            activeerRegulVoorKwartaalOpdrachten(rekenTijd, opdrachtenKwartaal, regulManager, Regulkode.HERREKENEN_NOODZAKELIJK, false);
        }
    }

    private void zetOpNulRszVrBr(LoonElementManager manager) {
        Collection<LoonElement> loonElementen = manager.getPersoonsElementen();
        for (LoonElement element : loonElementen) {
            Opper opper = element.getOpper();
            if (isVrijwilligeBrandweer(opper.getRszppo().getCategorie())) {
                for (MoneyKey vrBrRszKey : VR_BR_RSZ_KEYS) {
                    element.putProperty(vrBrRszKey, Money.ZERO);
                }
            }
        }

    }

    private void analyseerHuidigeMaandVrBr(LoonElementManager manager, MoneyMap<OpdrachtDatumKey> keyToBasisRsz, RekenTijd rekenTijd) {
        Collection<LoonElement> loonElementen = manager.getPersoonsElementen();
        for (LoonElement element : loonElementen) {
            Opper opper = element.getOpper();
            if (isVrijwilligeBrandweer(opper.getRszppo().getCategorie())) {
                AardKodeExtensie looncode = element.getAardKodeExtensie();
                boolean hasBasRsz = false;
                RegimeRszppo regimeRszppo = regimeRszppoService
                        .getByCategorieLoonCodeEnDatum(opper.getRszppo().getCategorie().getCode(), looncode.getCode(), rekenTijd.eindDatum);
                if (regimeRszppo != null) {
                    char regime = regimeRszppo.getRegime();
                    hasBasRsz = regime == '2' || regime == 'C' || regime == 'B';
                }
                OpdrachtDatumKey opdrachtDatum = new OpdrachtDatumKey(opper.getOpdracht(), rekenTijd.beginDatum);
                if (hasBasRsz) {
                    keyToBasisRsz.addToMoney(opdrachtDatum, element.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY));
                }
            }
        }
    }

    private Money analyseerKwartaalResultatenVrBr(
            List<RekenHoofd> kwartaalResultaten, MoneyMap<OpdrachtDatumKey> keyToBasisRsz,
            LocalDate huidigeBeginDatum) {
        Money basis = Money.ZERO;
        for (RekenHoofd hoofd : kwartaalResultaten) {
            if (!hoofd.getBeginDatum().equals(huidigeBeginDatum) && isVrijwilligeBrandweer(hoofd.getCategorie())) {
                OpdrachtDatumKey opdrachtDatum = new OpdrachtDatumKey(hoofd.getOpdracht(), hoofd.getBeginDatum());
                LocalDate gegevensDatum = hoofd.getBeginDatum().dayOfMonth().withMaximumValue();
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    AardKodeExtensie looncode = lijn.getAardKodeExtensie();
                    boolean hasBasRsz = false;
                    RegimeRszppo regimeRszppo =
                            regimeRszppoService.getByCategorieLoonCodeEnDatum(hoofd.getCategorie().getCode(), looncode.getCode(), gegevensDatum);
                    if (regimeRszppo != null) {
                        char regime = regimeRszppo.getRegime();
                        hasBasRsz = regime == '2' || regime == 'C' || regime == 'B';
                    }

                    for (RekenBedrag bedrag : lijn.getRekenBedragen()) {
                        MoneyKey key = RekenTools.bedragTypeToMoneyKey(bedrag.getBedragType(), lijn.getRegimeBv(), hoofd.getBeginDatum());
                        if (key == RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY) {
                            if (hasBasRsz) {
                                basis = basis.add(bedrag.getBedrag());
                                if (bedrag.getBedrag().signum() != 0) {
                                    keyToBasisRsz.addToMoney(opdrachtDatum, Money.ZERO);
                                }
                            }
                        } else {
                            if (key == RekenBasisRszKey.BASIS_RSZ_KEY) {
                                keyToBasisRsz.addToMoney(opdrachtDatum, bedrag.getBedrag());
                            }
                        }
                    }
                }
            }
        }
        return basis;
    }

    protected void activeerRegulVoorKwartaalOpdrachten(
            RekenTijd rekenTijd, List<Opdracht> opdrachtenKwartaal, RegulManager regulManager, Regulkode regulKode, boolean currentMonth) {
        Quarter kwartaal = new Quarter(rekenTijd.beginDatum);
        List<LocalDate> kwartaalDatums = ImmutableList.of(kwartaal.getStart(), kwartaal.getStart().plusMonths(1), kwartaal.getStart().plusMonths(2));
        for (Opdracht opdracht : opdrachtenKwartaal) {
            LocalDateInterval periode = new LocalDateInterval(opdracht.getBeginDatum(), opdracht.getEindDatum());
            for (LocalDate beginDatum : kwartaalDatums) {
                if (periode.contains(beginDatum) && (currentMonth || !beginDatum.equals(rekenTijd.beginDatum))) {
                    regulManager.addRegul(beginDatum, opdracht, regulKode);
                }
            }
        }
    }


    private record OpdrachtDatumKey(Opdracht opdracht, LocalDate beginDatum) {
    }
}
